#include<bits/stdc++.h>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define Clear(a) memset(a,0,sizeof(a))
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
inline long long Read()
{
	long long res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=1e5+10,INF=0x3f3f3f3f;
struct FHQ
{
	struct node{int l,r,key,val;}t[N<<1];int cnt,Rt,T1,T2,T3;
	inline int Node(int k){t[++cnt].key=rand();t[cnt].val=k;t[cnt].l=t[cnt].r=0;return cnt;}
	void spilt(int cur,int val,int &x,int &y)
	{
		if(!cur){x=y=0;return;}
		if(t[cur].val<=val)x=cur,spilt(t[cur].r,val,t[cur].r,y);
		else y=cur,spilt(t[cur].l,val,x,t[cur].l); 
	}
	int merge(int x,int y)
	{
		if(!x||!y)return x|y;
		if(t[x].key<t[y].key){t[x].r=merge(t[x].r,y);return x;}
		t[y].l=merge(x,t[y].l);return y;
	}
	inline void ins(int k){spilt(Rt,k,T1,T2);Rt=merge(merge(T1,Node(k)),T2);}
	inline void del(int k){spilt(Rt,k,T1,T2);spilt(T1,k-1,T1,T3);Rt=merge(merge(merge(T1,t[T3].l),t[T3].r),T2);}
	inline int fnd(int k)
	{
		spilt(Rt,k,T1,T2);if(!T1){int cur=Rt=T2;while(t[cur].l)cur=t[cur].l;return t[cur].val;}
		int cur=T1;while(t[cur].r)cur=t[cur].r;Rt=merge(T1,T2);return t[cur].val;
	}
	inline void Clr(){cnt=Rt=0;return;}
}q;
long long exgcd(long long a,long long b,long long &x,long long &y)
	{long long res=a,tmp;b?(res=exgcd(b,a%b,x,y),tmp=x,x=y,y=tmp-a/b*y):(x=1,y=0);return res;}
