inline long long Mul(long long ai,long long b,long long m)//龟速乘
{
    long long s=0;
    while(b)
    {
        if(b&1) s=(s+ai)%m;
        ai=(ai<<1)%m;
        b>>=1;
    }
    return s;
}
long long a[N],p[N],mx;int atk[N];
inline void Solve()
{
	q.Clr();mx=0;int n=read(),m=read();rep(1,n,i)a[i]=Read();rep(1,n,i)p[i]=Read();rep(1,n,i)atk[i]=read();rep(1,m,i)q.ins(read());
	rep(1,n,i){int tmp=atk[i];atk[i]=q.fnd((int)min(1ll*INF,a[i]));q.del(atk[i]);q.ins(tmp);mx=max(mx,a[i]/atk[i]+(a[i]%atk[i]!=0));}
	long long ans=0,lcm=1,A,B,C,x,y;rep(1,n,i)
	{
		
		A=Mul(atk[i],lcm,p[i]);B=p[i];C=(a[i]%p[i]-Mul(atk[i],ans,p[i])%p[i]+p[i])%p[i];
		long long GCD=exgcd(A,B,x,y);if(C%GCD!=0){puts("-1");return;}x=(x%p[i]+p[i])%p[i];
		ans+=Mul(C/GCD,x,p[i]/GCD)*lcm;lcm=p[i]/GCD*lcm;
	}
	if(ans<mx)ans+=((mx-ans)/lcm+((mx-ans)%lcm!=0))*lcm;printf("%lld\n",ans);return;
}
int main(){int T=read();while(T--)Solve();return 0;}
